import typer

app = typer.Typer()

@app.command()
def greet(name: str):
    typer.echo(f'Hello {name}')

if __name__ == '__main__':
    app()

@app.command()
def greet(name: str, greeting: str = 'Hello'):
    typer.echo(f'{greeting} {name}')

@app.command()
def process(verbose: bool = False):
    if verbose:
        typer.echo('Verbose mode on')

@app.command()
def build(target: str):
    typer.secho(f'Building {target}', fg=typer.colors.CYAN)

@app.command()
def deploy(env: str = 'prod'):
    typer.secho(f'Deploying to {env}', fg=typer.colors.GREEN)

if __name__ == '__main__':
    app()
